+export function getDecayedScore(
+  events: FeedbackEvent[] = [],
+  halfLifeDays: number
+): number {
+  const now = new Date();
+  return events.reduce(
+    (sum, event) => sum + calculateDecayedValue(event, now, halfLifeDays),
+    0
+  );
